"use strict";(self.webpackChunkwebsite=self.webpackChunkwebsite||[]).push([[53],{1109:e=>{e.exports=JSON.parse('{"pluginId":"default","version":"current","label":"Next","banner":null,"badge":false,"noIndex":false,"className":"docs-version-current","isLast":true,"docsSidebars":{"docsSidebar":[{"type":"category","collapsible":false,"label":"Getting Started","items":[{"type":"link","label":"Making a connection","href":"/mongo4cats/docs/gettingstarted/connection","docId":"gettingstarted/connection","unlisted":false},{"type":"link","label":"Getting a collection","href":"/mongo4cats/docs/gettingstarted/collection","docId":"gettingstarted/collection","unlisted":false},{"type":"link","label":"Working with documents","href":"/mongo4cats/docs/gettingstarted/documents","docId":"gettingstarted/documents","unlisted":false}],"collapsed":false,"href":"/mongo4cats/docs/"},{"type":"category","collapsible":false,"label":"Operations","items":[{"type":"link","label":"Indexes","href":"/mongo4cats/docs/operations/indexes","docId":"operations/indexes","unlisted":false},{"type":"link","label":"Find","href":"/mongo4cats/docs/operations/find","docId":"operations/find","unlisted":false},{"type":"link","label":"Update","href":"/mongo4cats/docs/operations/update","docId":"operations/update","unlisted":false},{"type":"link","label":"Distinct","href":"/mongo4cats/docs/operations/distinct","docId":"operations/distinct","unlisted":false},{"type":"link","label":"Aggregate","href":"/mongo4cats/docs/operations/aggregate","docId":"operations/aggregate","unlisted":false},{"type":"link","label":"Watch (Change Streams)","href":"/mongo4cats/docs/operations/watch","docId":"operations/watch","unlisted":false},{"type":"link","label":"Transactions","href":"/mongo4cats/docs/operations/transactions","docId":"operations/transactions","unlisted":false},{"type":"link","label":"Bulk Writes","href":"/mongo4cats/docs/operations/bulk","docId":"operations/bulk","unlisted":false}],"collapsed":false,"href":"/mongo4cats/docs/operations"},{"type":"link","label":"Embedded MongoDB","href":"/mongo4cats/docs/embedded","docId":"embedded","unlisted":false},{"type":"link","label":"Circe","href":"/mongo4cats/docs/circe","docId":"circe","unlisted":false},{"type":"link","label":"ZIO","href":"/mongo4cats/docs/zio","docId":"zio","unlisted":false}]},"docs":{"circe":{"id":"circe","title":"Circe","description":"The mongo4cats-circe module bridges Circe and MongoDB\'s BSON encoding. It lets you use Circe\'s automatic codec derivation to read and write Scala case classes directly to and from MongoDB collections, without writing any BSON codec boilerplate.","sidebar":"docsSidebar"},"embedded":{"id":"embedded","title":"Embedded MongoDB (Testing)","description":"The mongo4cats-embedded module starts a temporary in-process MongoDB instance for use in tests. It is built on top of de.flapdoodle.embed.mongo and downloads the appropriate MongoDB binary automatically on the first run (cached in ~/.embedmongo afterwards).","sidebar":"docsSidebar"},"gettingstarted/collection":{"id":"gettingstarted/collection","title":"Getting a collection","description":"MongoCollection","sidebar":"docsSidebar"},"gettingstarted/connection":{"id":"gettingstarted/connection","title":"Making a connection","description":"MongoClient","sidebar":"docsSidebar"},"gettingstarted/documents":{"id":"gettingstarted/documents","title":"Working with documents","description":"MongoDB stores data records as BSON documents. BSON is a binary representation of JSON, though it supports more data types \u2014 including ObjectId, Instant/date, Decimal128, binary data, and more.","sidebar":"docsSidebar"},"index":{"id":"index","title":"Getting started","description":"Maven Central","sidebar":"docsSidebar"},"operations":{"id":"operations","title":"Operations","description":"Operations listed in this section describe the procedures that can be executed on a MongoCollection[F, T] instance. All operations return values wrapped in the effect type F[_] (typically IO for Cats Effect or Task for ZIO). Long-running queries can alternatively be consumed as a stream.","sidebar":"docsSidebar"},"operations/aggregate":{"id":"operations/aggregate","title":"Aggregate","description":"Aggregation pipelines process documents through a sequence of stages, where the output of each stage is the input to the next. This is MongoDB\'s most powerful query mechanism \u2014 it supports grouping, joining collections, computing new fields, bucketing, full-text search, vector search, and more.","sidebar":"docsSidebar"},"operations/bulk":{"id":"operations/bulk","title":"Bulk Writes","description":"Bulk write operations let you send multiple insert, update, replace, and delete commands to MongoDB in a single network round trip. This is significantly more efficient than executing each operation individually when you need to modify many documents at once.","sidebar":"docsSidebar"},"operations/distinct":{"id":"operations/distinct","title":"Distinct","description":"The distinct operation returns all unique values for a specified field across a collection, equivalent to SQL\'s SELECT DISTINCT. It is useful for building autocomplete lists, enumerating categories, or checking what values actually exist in production data.","sidebar":"docsSidebar"},"operations/find":{"id":"operations/find","title":"Find","description":"The find operation retrieves documents from a collection. It supports filtering, sorting, pagination, field projection, and streaming for large result sets.","sidebar":"docsSidebar"},"operations/indexes":{"id":"operations/indexes","title":"Indexes","description":"Indexes make queries efficient by allowing MongoDB to find documents without scanning the entire collection. They also enable unique constraints, TTL (time-to-live) document expiry, geospatial queries, text search, and more.","sidebar":"docsSidebar"},"operations/transactions":{"id":"operations/transactions","title":"Transactions","description":"MongoDB multi-document transactions provide ACID guarantees across multiple operations and collections. They require a replica set (MongoDB 4.0+) or a sharded cluster (MongoDB 4.2+). Standalone deployments do not support transactions.","sidebar":"docsSidebar"},"operations/update":{"id":"operations/update","title":"Update","description":"Update operations modify fields and values in existing documents. mongo4cats provides a fluent, chainable Update builder that compiles to the standard MongoDB update operators.","sidebar":"docsSidebar"},"operations/watch":{"id":"operations/watch","title":"Watch (Change Streams)","description":"Change streams let your application react to changes in a MongoDB collection in real time. When documents are inserted, updated, replaced, or deleted, the stream emits a change event document describing what happened.","sidebar":"docsSidebar"},"zio":{"id":"zio","title":"ZIO","description":"The mongo4cats-zio module provides ZMongoClient, ZMongoDatabase, and ZMongoCollection \u2014 type aliases that replace Cats Effect\'s IO with Task and FS2 streams with ZStream. The entire API surface is identical to the Cats Effect module; only the effect type changes.","sidebar":"docsSidebar"}}}')}}]);